CREATE VIEW results.v_neuro_assessment AS SELECT person_id, observation_datetime, MAX(CASE WHEN observation_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=4253928) THEN value_as_number END) AS gcs_total, MAX(CASE WHEN observation_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=40488434) THEN value_as_number END) AS rass_score FROM cdm.observation GROUP BY 1,2;